def mode_count(nums):
    """
    Returns the number of distinct values that tie for the highest frequency.

    Args:
        nums (list): A list of numbers.

    Returns:
        int: The count of distinct modes.
    """
    if not nums:
        return 0  # Edge case: empty list returns 0

    freq = {}
    max_freq = 0
    modes = set()

    for num in nums:
        freq[num] = freq.get(num, 0) + 1
        if freq[num] > max_freq:
            max_freq = freq[num]
            modes = {num}
        elif freq[num] == max_freq:
            modes.add(num)

    return len(modes)
